@page "/apply"
@rendermode InteractiveServer
@using sv_d62d623cbeaf4c378e9567ca8d974a2d.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="mb-4">
        <div class="d-flex justify-content-between position-relative">
            @for (int i = 0; i < _stepLabels.Length; i++)
            {
                var step = i + 1;
                var isCompleted = step < _currentStep;
                var isCurrent = step == _currentStep;
                var isFuture = step > _currentStep;

                <div class="text-center flex-fill position-relative">
                    <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepCircleClass(step)"
                            style="width: 40px; height: 40px; font-size: 0.85rem;"
                            disabled="@(isFuture || _submitted)"
                            @onclick="() => GoToStep(step)">
                        @if (isCompleted)
                        {
                            <span>&#10003;</span>
                        }
                        else
                        {
                            @step
                        }
                    </button>
                    <div class="small mt-1 @(isFuture ? "text-muted" : (isCurrent ? "fw-bold" : ""))">
                        @_stepLabels[i]
                    </div>
                </div>
            }
        </div>
        <div class="progress mt-2" style="height: 4px;">
            <div class="progress-bar" style="width: @((_currentStep - 1) * 25)%"></div>
        </div>
    </nav>

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="bg-success text-white rounded-circle d-inline-flex align-items-center justify-content-center"
                      style="width: 64px; height: 64px; font-size: 1.5rem;">&#10003;</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@_applicationId</strong></p>
            <p class="text-muted">We'll review your application and be in touch soon.</p>
        </div>
    }
    else
    {
        @* ───── Validation Errors ───── *@
        @if (_errors.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var error in _errors)
                    {
                        <li>@error</li>
                    }
                </ul>
            </div>
        }

        @* ───── Step 1: Personal Info ───── *@
        @if (_currentStep == 1)
        {
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Full Name <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_fullName" @bind:event="oninput" placeholder="Jane Doe" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="_email" @bind:event="oninput" placeholder="jane@example.com" />
                        @if (_emailValidating)
                        {
                            <div class="form-text text-info">Validating email…</div>
                        }
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" placeholder="(555) 123-4567" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Address <span class="text-danger">*</span></label>
                        <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput" placeholder="123 Main St, City, State"></textarea>
                    </div>
                </div>
            </div>
        }

        @* ───── Step 2: Work History ───── *@
        @if (_currentStep == 2)
        {
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-outline-primary" @onclick="AddWorkEntry">+ Add Another Position</button>
                </div>
                <div class="card-body">
                    @for (int i = 0; i < _workEntries.Count; i++)
                    {
                        var idx = i;
                        var entry = _workEntries[idx];
                        <div class="border rounded p-3 mb-3 @(idx > 0 ? "" : "")">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Position @(idx + 1)</h6>
                                @if (_workEntries.Count > 1)
                                {
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                                }
                            </div>
                            <div class="row">
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Company <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="entry.Company" @bind:event="oninput" />
                                </div>
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="entry.Title" @bind:event="oninput" />
                                </div>
                            </div>
                            <div class="row">
                                <div class="col-md-4 mb-3">
                                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                    <input type="date" class="form-control" @bind="entry.StartDate" />
                                </div>
                                <div class="col-md-4 mb-3">
                                    <label class="form-label">End Date</label>
                                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                                </div>
                                <div class="col-md-4 mb-3 d-flex align-items-end">
                                    <div class="form-check">
                                        <input class="form-check-input" type="checkbox" @bind="entry.IsCurrent" id="current-@idx" />
                                        <label class="form-check-label" for="current-@idx">Currently working here</label>
                                    </div>
                                </div>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" @bind="entry.Description" @bind:event="oninput"></textarea>
                            </div>
                        </div>
                    }
                </div>
            </div>
        }

        @* ───── Step 3: References ───── *@
        @if (_currentStep == 3)
        {
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">References</h5>
                    @if (_references.Count < 3)
                    {
                        <button class="btn btn-sm btn-outline-primary" @onclick="AddReference">+ Add Reference</button>
                    }
                </div>
                <div class="card-body">
                    @for (int i = 0; i < _references.Count; i++)
                    {
                        var idx = i;
                        var refEntry = _references[idx];
                        <div class="border rounded p-3 mb-3">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Reference @(idx + 1)</h6>
                                @if (_references.Count > 2)
                                {
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(idx)">Remove</button>
                                }
                            </div>
                            <div class="row">
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Name <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="refEntry.Name" @bind:event="oninput" />
                                </div>
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                    <input class="form-control" @bind="refEntry.Relationship" @bind:event="oninput" placeholder="e.g. Former Manager" />
                                </div>
                            </div>
                            <div class="row">
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Email <span class="text-danger">*</span></label>
                                    <input type="email" class="form-control" @bind="refEntry.Email" @bind:event="oninput" />
                                </div>
                                <div class="col-md-6 mb-3">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" @bind="refEntry.Phone" @bind:event="oninput" />
                                </div>
                            </div>
                        </div>
                    }
                </div>
            </div>
        }

        @* ───── Step 4: Cover Letter ───── *@
        @if (_currentStep == 4)
        {
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
                <div class="card-body">
                    <textarea class="form-control" rows="12" @bind="_coverLetter" @bind:event="oninput"
                              maxlength="2000"
                              placeholder="Tell us why you'd be a great fit…"></textarea>
                    <div class="form-text text-end">@_coverLetter.Length / 2000 characters</div>
                </div>
            </div>
        }

        @* ───── Step 5: Review & Submit ───── *@
        @if (_currentStep == 5)
        {
            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
                </div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-3">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <span class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") –
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </span>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> — @r.Relationship<br />
                            <span class="text-muted">@r.Email · @r.Phone</span>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-sm btn-link" @onclick='() => GoToStep(4)'>Edit</button>
                </div>
                <div class="card-body">
                    <p style="white-space: pre-wrap;">@_coverLetter</p>
                </div>
            </div>
        }

        @* ───── Navigation Buttons ───── *@
        <div class="d-flex justify-content-between mt-4">
            <div>
                @if (_currentStep > 1)
                {
                    <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">
                        &larr; Back
                    </button>
                }
            </div>
            <div>
                @if (_currentStep < 5)
                {
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Next &rarr;
                    </button>
                }
                else
                {
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isProcessing">
                        @if (_isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                            <span>Submitting…</span>
                        }
                        else
                        {
                            <span>Submit Application</span>
                        }
                    </button>
                }
            </div>
        </div>
    }
</div>

@code {
    private static readonly string[] _stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep = 1;
    private bool _submitted;
    private bool _isProcessing;
    private bool _emailValidating;
    private int _applicationId;
    private List<string> _errors = new();

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string _coverLetter = "";

    private string StepCircleClass(int step)
    {
        if (step < _currentStep) return "btn-success text-white";
        if (step == _currentStep) return "btn-primary text-white";
        return "btn-outline-secondary";
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _errors.Clear();
            _currentStep = step;
        }
    }

    private void PreviousStep()
    {
        _errors.Clear();
        if (_currentStep > 1) _currentStep--;
    }

    private async Task NextStep()
    {
        _errors.Clear();

        if (!ValidateCurrentStep())
            return;

        if (_currentStep == 1)
        {
            _emailValidating = true;
            _isProcessing = true;
            StateHasChanged();

            var valid = await ApplicationService.ValidateEmailAsync(_email);
            _emailValidating = false;
            _isProcessing = false;

            if (!valid)
            {
                _errors.Add("Please enter a valid email address.");
                return;
            }
        }

        _currentStep++;
    }

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(_fullName)) _errors.Add("Full name is required.");
                if (string.IsNullOrWhiteSpace(_email)) _errors.Add("Email is required.");
                if (string.IsNullOrWhiteSpace(_phone)) _errors.Add("Phone is required.");
                if (string.IsNullOrWhiteSpace(_address)) _errors.Add("Address is required.");
                break;

            case 2:
                for (int i = 0; i < _workEntries.Count; i++)
                {
                    var e = _workEntries[i];
                    if (string.IsNullOrWhiteSpace(e.Company)) _errors.Add($"Position {i + 1}: Company is required.");
                    if (string.IsNullOrWhiteSpace(e.Title)) _errors.Add($"Position {i + 1}: Job title is required.");
                    if (e.StartDate == default) _errors.Add($"Position {i + 1}: Start date is required.");
                }
                break;

            case 3:
                for (int i = 0; i < _references.Count; i++)
                {
                    var r = _references[i];
                    if (string.IsNullOrWhiteSpace(r.Name)) _errors.Add($"Reference {i + 1}: Name is required.");
                    if (string.IsNullOrWhiteSpace(r.Relationship)) _errors.Add($"Reference {i + 1}: Relationship is required.");
                    if (string.IsNullOrWhiteSpace(r.Email)) _errors.Add($"Reference {i + 1}: Email is required.");
                    if (string.IsNullOrWhiteSpace(r.Phone)) _errors.Add($"Reference {i + 1}: Phone is required.");
                }
                break;

            case 4:
                if (string.IsNullOrWhiteSpace(_coverLetter)) _errors.Add("Cover letter is required.");
                break;
        }

        return _errors.Count == 0;
    }

    private async Task SubmitApplication()
    {
        _isProcessing = true;
        _errors.Clear();

        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var workHistory = new WorkHistory(_workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? "")
        ).ToList());
        var refs = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)
        ).ToList();

        var application = new JobApplication(personal, workHistory, refs, _coverLetter);

        try
        {
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errors.Add($"Submission failed: {ex.Message}");
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // Work entry helpers
    private void AddWorkEntry() => _workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    // Reference helpers
    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2) _references.RemoveAt(index);
    }

    // Mutable view-models for form binding
    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}
